public class Main {
    public static void main(String[] args) {
        // Autoboxing: int → Integer
        Integer num1 = 100;  // 自動的にInteger.valueOf(100)が呼ばれる

        // Unboxing: Integer → int
        int num2 = num1;  // 自動的にnum1.intValue()が呼ばれる

        // ArrayListでのAutoboxing
        java.util.ArrayList<Integer> list = new java.util.ArrayList<>();
        list.add(42);  // int 42がAutoboxingされてInteger(42)として追加
        int val = list.get(0);  // Unboxingされてintとしてvalに代入

        System.out.println(num1);  // 100
        System.out.println(num2);  // 100
        System.out.println(val);   // 42
    }
}

public class Main {
