public class Main {
    // mainメソッドの定義
    public static void main(String[] args) {
        // 変数の宣言と初期化
        String s = "Hello Java";

        System.out.println(s.length());       // 10
        System.out.println(s.charAt(0));       // H
        System.out.println(s.charAt(6));       // J
        System.out.println(s.indexOf('J'));    // 6
        System.out.println(s.indexOf("Java")); // 6
        System.out.println(s.indexOf('Z'));    // -1（見つからない場合）

        // substring(beginIndex) - beginIndexから末尾まで
        System.out.println(s.substring(6));    // Java
        // substring(beginIndex, endIndex) - beginIndexからendIndex未満
        System.out.println(s.substring(0, 5)); // Hello
    }
}

