public class Main {
    // mainメソッドの定義
    public static void main(String[] args) {
        // 変数の宣言と初期化
        String s = "Hello";
        s.toUpperCase();  // 新しい文字列が作られるが、sは変わらない
        System.out.println(s);  // Hello（元のまま）

        String upper = s.toUpperCase();  // 戻り値を受け取る
        System.out.println(upper);  // HELLO

        String s2 = s.replace('l', 'r');
        System.out.println(s);   // Hello（元のまま）
        System.out.println(s2);  // Herro

        String s3 = s.concat(" World");
        System.out.println(s);   // Hello（元のまま）
        System.out.println(s3);  // Hello World
    }
}

