        StringBuilder sb = new StringBuilder();
        sb.append("Java").append(" ").append("Silver").insert(0, "★");
        System.out.println(sb);  // ★Java Silver

        // これは以下と同じ意味
        StringBuilder sb2 = new StringBuilder();
        sb2.append("Java");
        sb2.append(" ");
        sb2.append("Silver");
        sb2.insert(0, "★");
        System.out.println(sb2);  // ★Java Silver
    }
}

