import java.time.LocalDate;

public class Main {
    public static void main(String[] args) {
        // 現在の日付
        LocalDate today = LocalDate.now();
        System.out.println(today);  // 例: 2026-04-07

        // 任意の日付を指定
        LocalDate date = LocalDate.of(2025, 1, 15);
        System.out.println(date);  // 2025-01-15

        // 各値の取得
        System.out.println(date.getYear());        // 2025
        System.out.println(date.getMonthValue());  // 1
        System.out.println(date.getDayOfMonth());  // 15

        // 日付の加減算（元のオブジェクトは変わらない）
        LocalDate nextWeek = date.plusDays(7);
        System.out.println(nextWeek);  // 2025-01-22

        LocalDate lastMonth = date.minusMonths(1);
        System.out.println(lastMonth);  // 2024-12-15
    }
}

import java.time.LocalDateTime;

public class Main {
    public static void main(String[] args) {
        // 現在の日時
        LocalDateTime now = LocalDateTime.now();
        System.out.println(now);  // 例: 2026-04-07T14:30:15.123

        // 任意の日時を指定
        LocalDateTime dt = LocalDateTime.of(2025, 6, 15, 10, 30, 0);
        System.out.println(dt);  // 2025-06-15T10:30

        // 日時の加減算
        LocalDateTime later = dt.plusHours(3);
        System.out.println(later);  // 2025-06-15T13:30

        LocalDateTime earlier = dt.minusDays(2).minusMinutes(15);
        System.out.println(earlier);  // 2025-06-13T10:15

        // LocalDateTimeは不変
        dt.plusYears(1);  // 新しいオブジェクトが返されるがdtは変わらない
        System.out.println(dt);  // 2025-06-15T10:30
    }
}

